from pathlib import Path
import re, collections
root=Path('shaders/ifs_and_geometric')
funcs=collections.defaultdict(list)
uniforms=collections.defaultdict(list)
for p in sorted(root.glob('*.frag')):
    txt=p.read_text(errors='ignore')
    for m in re.finditer(r'^(?:float|vec[234]|mat[234]|int|bool)\s+([A-Za-z_]\w*)\s*\([^;]*\)\s*\{', txt, re.M):
        funcs[m.group(1)].append(p.name)
    for m in re.finditer(r'^uniform\s+([^;]+);', txt, re.M):
        uniforms[m.group(1).strip()].append(p.name)
print('duplicate funcs')
for name, files in sorted(funcs.items()):
    if len(files)>1:
        print(name, len(files), ', '.join(files[:8]), '...' if len(files)>8 else '')
print('uniform declarations count')
for uni, files in sorted(uniforms.items(), key=lambda kv:(-len(kv[1]), kv[0]))[:20]:
    print(len(files), uni)
